const e=JSON.parse('{"key":"v-00ce9131","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%9C%B0%E9%9C%87%E7%89%88%EF%BC%89/02-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E4%BA%8C.html","title":"道氏理论二","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["道氏理论"],"order":2,"description":"道氏理论二 道氏的三种运动 股票的平均价格指数由三种运动构成。也许在同一个时间中就会包含这三种运动。其中首要的，也是最为重要的就是主要趋势运动：股市整体的向上或向下的运动，也就是众所周知的牛市或熊市，其持续时间也许会是几年。处于第二位的，也是最容易迷惑人的运动，就是次一级的反应运动：对于主要趋势是牛市的市场中，次一级的反应运动就是重要回调的下跌运动；而在主要趋势是熊市的市场中，次一级的反应运动就是反弹的上升运动。这些反应运动通常持续3周到数月。处于第三位的，通常也是不重要的运动，就是平均指数的日间波动。 每一位汽车驾驶员都会记得在上第一堂驾驶课时，在心、手和脚之间发生的混乱状态。教练会坐在身边，坚持要求他把观察路况和脚离开油门踩刹车这些动作连贯起来并同时完成。可是随着经验积累，使用油门和刹车已经成了一种近似的条件反射，观察路况的习惯巡最终养成，学习者再第一次尝试理解道氏的三种价格运动时。可能也会有在类似的混乱。可是迟早他们对三种运动的识别和认知几乎会成为自动的心理和视觉过程。次级的反应运动所造成的市场趋势的暂时改变，对于市场的效用就像是刹车对汽车的作用一样：它们都是对运动超速的抑制。对于造成汽车减慢和加速的油门，可以与股市的日间波动相比照，在有些交易日，日间波动会与基本趋势和次级运动同方向；而在另一些交易日，则会相反。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%9C%B0%E9%9C%87%E7%89%88%EF%BC%89/02-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E4%BA%8C.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"道氏理论二"}],["meta",{"property":"og:description","content":"道氏理论二 道氏的三种运动 股票的平均价格指数由三种运动构成。也许在同一个时间中就会包含这三种运动。其中首要的，也是最为重要的就是主要趋势运动：股市整体的向上或向下的运动，也就是众所周知的牛市或熊市，其持续时间也许会是几年。处于第二位的，也是最容易迷惑人的运动，就是次一级的反应运动：对于主要趋势是牛市的市场中，次一级的反应运动就是重要回调的下跌运动；而在主要趋势是熊市的市场中，次一级的反应运动就是反弹的上升运动。这些反应运动通常持续3周到数月。处于第三位的，通常也是不重要的运动，就是平均指数的日间波动。 每一位汽车驾驶员都会记得在上第一堂驾驶课时，在心、手和脚之间发生的混乱状态。教练会坐在身边，坚持要求他把观察路况和脚离开油门踩刹车这些动作连贯起来并同时完成。可是随着经验积累，使用油门和刹车已经成了一种近似的条件反射，观察路况的习惯巡最终养成，学习者再第一次尝试理解道氏的三种价格运动时。可能也会有在类似的混乱。可是迟早他们对三种运动的识别和认知几乎会成为自动的心理和视觉过程。次级的反应运动所造成的市场趋势的暂时改变，对于市场的效用就像是刹车对汽车的作用一样：它们都是对运动超速的抑制。对于造成汽车减慢和加速的油门，可以与股市的日间波动相比照，在有些交易日，日间波动会与基本趋势和次级运动同方向；而在另一些交易日，则会相反。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-02-04T15:27:55.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"道氏理论"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-02-04T15:27:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"道氏理论二\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-02-04T15:27:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"道氏的三种运动","slug":"道氏的三种运动","link":"#道氏的三种运动","children":[]},{"level":2,"title":"主要运动","slug":"主要运动","link":"#主要运动","children":[]},{"level":2,"title":"熊市","slug":"熊市","link":"#熊市","children":[]},{"level":2,"title":"牛市","slug":"牛市","link":"#牛市","children":[]},{"level":2,"title":"次级反应运动","slug":"次级反应运动","link":"#次级反应运动","children":[]}],"git":{"createdTime":1707060475000,"updatedTime":1707060475000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":54.35,"words":16306},"filePathRelative":"证券交易/道氏理论（地震版）/02-道氏理论二.md","localizedDate":"2024年1月17日","excerpt":"<h1> 道氏理论二</h1>\\n<h2> 道氏的三种运动</h2>\\n<p>股票的平均价格指数由三种运动构成。也许在同一个时间中就会包含这三种运动。其中首要的，也是最为重要的就是主要趋势运动：股市整体的向上或向下的运动，也就是众所周知的牛市或熊市，其持续时间也许会是几年。处于第二位的，也是最容易迷惑人的运动，就是次一级的反应运动：对于主要趋势是牛市的市场中，次一级的反应运动就是重要回调的下跌运动；而在主要趋势是熊市的市场中，次一级的反应运动就是反弹的上升运动。这些反应运动通常持续3周到数月。处于第三位的，通常也是不重要的运动，就是平均指数的日间波动。</p>\\n<p>每一位汽车驾驶员都会记得在上第一堂驾驶课时，在心、手和脚之间发生的混乱状态。教练会坐在身边，坚持要求他把观察路况和脚离开油门踩刹车这些动作连贯起来并同时完成。可是随着经验积累，使用油门和刹车已经成了一种近似的条件反射，观察路况的习惯巡最终养成，学习者再第一次尝试理解道氏的三种价格运动时。可能也会有在类似的混乱。可是迟早他们对三种运动的识别和认知几乎会成为自动的心理和视觉过程。次级的反应运动所造成的市场趋势的暂时改变，对于市场的效用就像是刹车对汽车的作用一样：它们都是对运动超速的抑制。对于造成汽车减慢和加速的油门，可以与股市的日间波动相比照，在有些交易日，日间波动会与基本趋势和次级运动同方向；而在另一些交易日，则会相反。</p>","autoDesc":true}');export{e as data};
